// Ambil base64 gambar dari Gemini, ubah jadi binary untuk diupload ke Supabase.
const parts = $json.candidates?.[0]?.content?.parts || [];
const imgPart = parts.find(p => p.inlineData || p.inline_data);
const inline = imgPart && (imgPart.inlineData || imgPart.inline_data);
if (!inline || !inline.data) {
  throw new Error('Gemini tidak mengembalikan gambar. Cek model image generation / kuota API.');
}
const p = $('Parse Caption').item.json;
return [{
  json: { caption: p.caption, hashtags: p.hashtags, image_prompt: p.image_prompt, filename: p.filename },
  binary: { data: { data: inline.data, mimeType: inline.mimeType || inline.mime_type || 'image/png', fileName: p.filename } }
}];

const p = $('Parse Caption').item.json;
const PROJECT = 'GANTI_PROJECT';
const publicUrl = `https://${PROJECT}.supabase.co/storage/v1/object/public/content-images/${p.filename}`;
return [{ json: {
  caption: p.caption,
  hashtags: p.hashtags,
  image_prompt: p.image_prompt,
  image_url: publicUrl
} }];
